public class DoWhile {
    public static void main(String[] args) {
        int n = 1;
        do {
            System.out.print(n + " ");
            n *= 2;
        } while (n <= 16);
        System.out.println();

        int x = 100;
        do {
            System.out.print(x + " ");
            x *= 2;
        } while (x <= 16);
        System.out.println();
    }
}
